            .read => 0x001, // POLLIN
            .write => 0x004, // POLLOUT
            .read_write => 0x001 | 0x004,
        };
        _ = self.ring.poll_add(@intCast(fd), poll_mask, @intCast(fd)) catch {};
        _ = self.ring.submit() catch {};
    }

